import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    type: 'order:confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed.',
    status: 'sent',
    sentAt: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('record', () => {
    it('should record a notification and return a log entry', () => {
      const notification = makeNotification();
      const log = historyService.record(notification);

      expect(log.id).toBe('nlog-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order:confirmation');
      expect(log.subject).toBe('Order Confirmation: order-1');
      expect(log.status).toBe('sent');
      expect(log.timestamp).toEqual(new Date('2026-01-15T10:00:00Z'));
    });

    it('should generate sequential IDs', () => {
      const log1 = historyService.record(makeNotification());
      const log2 = historyService.record(makeNotification({ id: 'notif-0002' }));

      expect(log1.id).toBe('nlog-0001');
      expect(log2.id).toBe('nlog-0002');
    });

    it('should persist to the repository', () => {
      historyService.record(makeNotification());
      expect(repository.count()).toBe(1);
    });

    it('should record failed notifications', () => {
      const log = historyService.record(makeNotification({ status: 'failed' }));
      expect(log.status).toBe('failed');
    });

    it('should preserve metadata', () => {
      const log = historyService.record(
        makeNotification({ metadata: { orderId: 'order-1' } }),
      );
      expect(log.metadata).toEqual({ orderId: 'order-1' });
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.record(
        makeNotification({
          recipient: 'alice@example.com',
          type: 'order:confirmation',
          channel: 'email',
          status: 'sent',
          sentAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'order:status-update',
          channel: 'webhook',
          status: 'failed',
          sentAt: new Date('2026-01-16T10:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0003',
          recipient: 'alice@example.com',
          type: 'user:welcome',
          channel: 'email',
          status: 'sent',
          sentAt: new Date('2026-01-17T10:00:00Z'),
        }),
      );
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'order:confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order:confirmation');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        from: new Date('2026-01-16T00:00:00Z'),
        to: new Date('2026-01-17T23:59:59Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        channel: 'email',
        status: 'sent',
      });
      expect(results).toHaveLength(2);
    });

    it('should return all when no filters specified', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });

    it('should return empty when no matches', () => {
      const results = historyService.query({ recipient: 'unknown@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('getByRecipient', () => {
    it('should return logs for specific recipient', () => {
      historyService.record(makeNotification({ recipient: 'alice@example.com' }));
      historyService.record(
        makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }),
      );

      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });
  });

  describe('getByType', () => {
    it('should return logs for specific type', () => {
      historyService.record(makeNotification({ type: 'order:confirmation' }));
      historyService.record(
        makeNotification({ id: 'notif-0002', type: 'order:status-update' }),
      );

      const results = historyService.getByType('order:confirmation');
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order:confirmation');
    });
  });

  describe('getByDateRange', () => {
    it('should return logs within date range', () => {
      historyService.record(
        makeNotification({ sentAt: new Date('2026-01-10T10:00:00Z') }),
      );
      historyService.record(
        makeNotification({ id: 'notif-0002', sentAt: new Date('2026-01-20T10:00:00Z') }),
      );

      const results = historyService.getByDateRange(
        new Date('2026-01-09T00:00:00Z'),
        new Date('2026-01-15T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
    });
  });

  describe('count', () => {
    it('should return count of logged notifications', () => {
      expect(historyService.count()).toBe(0);
      historyService.record(makeNotification());
      expect(historyService.count()).toBe(1);
    });
  });

  describe('getById', () => {
    it('should return a specific log entry', () => {
      historyService.record(makeNotification());
      const log = historyService.getById('nlog-0001');
      expect(log).toBeDefined();
      expect(log?.recipient).toBe('alice@example.com');
    });

    it('should return undefined for unknown ID', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications when events are emitted', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('order:confirmation');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.channel).toBe('in-app');
    });

    it('should log multiple notifications from different events', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(historyService.count()).toBe(2);
      const byType = historyService.getByType('order:status-update');
      expect(byType).toHaveLength(1);
    });

    it('should capture delivery status in history', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      const logs = historyService.query({});
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.channel).toBe('in-app');
      expect(logs[0]?.subject).toContain('Order Update');
    });
  });
});
